using namespace std;
//
通用 切割函数 函数 将字符串
str
根据
delimiter
进行切割
vector<string> split(const
string& str, const string& delimiter) {
vector<string>
result;
size_t start = 0;
size_t end =
str.find(delimiter);
while (end !=
string::npos) {
result.push_back(str.substr(start, end - start));
start = end + delimiter.length();
end = str.find(delimiter, start);
}
//
添加最后一个部分
result.push_back(str.substr(start));
return result;
}
string
featureExtraction(vector<string>& docs) {
vector<int>
minCount(26, INT_MAX);
for (int i = 0; i <
docs.size(); i++) {
vector<int> curCount(26, 0);
//
统计出现次数
for (auto& c : docs[i]) {
curCount[c - 'a']++;
}
//
更新全局最小值
for (int j = 0; j < 26; j++) {
minCount[j] = min(minCount[j], curCount[j]);
}
}
//
构建结果
string res;
for (int i = 0; i <
26; i++) {
res.append(minCount[i], char('a' + i));
}
return res;
}
int main() {
string input;
getline(cin, input);
vector<string>
docs = split(input, " ");
string res =
featureExtraction(docs);
cout << res;
return 0;
}
JAVA
import java.util.*;
public class Main {
public static String
featureExtraction(String[] docs) {
int[] minCount = new int[26];
Arrays.fill(minCount, Integer.MAX_VALUE);
for (String doc : docs) {
int[] curCount = new int[26];
//
统计当前字符串字符出现次数
for (char c : doc.toCharArray()) {
curCount[c - 'a']++;
}
//
更新全局最小值
for (int i = 0; i < 26; i++) {
minCount[i] = Math.min(minCount[i], curCount[i]);
}
}
//
构建结果
StringBuilder res = new StringBuilder();
for (int i = 0; i < 26; i++) {
for (int j = 0; j < minCount[i]; j++) {
res.append((char) ('a' + i));
}
}
return res.toString();
}
public static void
main(String[] args) {
Scanner sc = new Scanner(System.in);
String input = sc.nextLine();
String[] docs = input.split(" ");
String res = featureExtraction(docs);
System.out.print(res);
}
}
